@startuml
!theme plain

class "PartnerController" as PartnerController {
  + partnerEndpoint : String
  - restTemplate : RestTemplate
  + PartnerController()
  + getAllEvents()
  + getEventById()
  + reserve()
}

package "rc" {
  package "consume" {
    package "rest" {
      PartnerController
    }
  }
}

@enduml
